  5→
  6→// Package repository provides job query functionality with filtering, pagination,
  7→// and security controls. This file contains the main query builders and security
  8→// checks for job retrieval operations.
  9→package repository
 10→
 11→import (
 12→	"context"
 13→	"errors"
 14→	"fmt"
 15→	"regexp"
 16→	"strings"
 17→	"time"
 18→
 19→	"github.com/ClusterCockpit/cc-backend/internal/config"
 20→	"github.com/ClusterCockpit/cc-backend/internal/graph/model"
 21→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 22→	"github.com/ClusterCockpit/cc-lib/v2/schema"
 23→	sq "github.com/Masterminds/squirrel"
 24→)
 25→
 26→const (
 27→	// Default initial capacity for job result slices
 28→	defaultJobsCapacity = 50
 29→)
 30→
 31→// QueryJobs retrieves jobs from the database with optional filtering, pagination,
 32→// and sorting. Security controls are automatically applied based on the user context.
 33→//
 34→// Parameters:
 35→//   - ctx: Context containing user authentication information
 36→//   - filters: Optional job filters (cluster, state, user, time ranges, etc.)
 37→//   - page: Optional pagination parameters (page number and items per page)
 38→//   - order: Optional sorting specification (column or footprint field)
 39→//
 40→// Returns a slice of jobs matching the criteria, or an error if the query fails.
 41→// The function enforces role-based access control through SecurityCheck.
 42→func (r *JobRepository) QueryJobs(
 43→	ctx context.Context,
 44→	filters []*model.JobFilter,
 45→	page *model.PageRequest,
 46→	order *model.OrderByInput,
 47→) ([]*schema.Job, error) {
 48→	query, qerr := SecurityCheck(ctx, sq.Select(jobColumns...).From("job"))
 49→	if qerr != nil {
 50→		return nil, qerr
 51→	}
 52→
 53→	if order != nil {
 54→		field := toSnakeCase(order.Field)
 55→		if order.Type == "col" {
 56→			switch order.Order {
 57→			case model.SortDirectionEnumAsc:
 58→				query = query.OrderBy(fmt.Sprintf("job.%s ASC", field))
 59→			case model.SortDirectionEnumDesc:
 60→				query = query.OrderBy(fmt.Sprintf("job.%s DESC", field))
 61→			default:
 62→				return nil, errors.New("invalid sorting order for column")
 63→			}
 64→		} else {
 65→			// Order by footprint JSON field values
 66→			query = query.Where("JSON_VALID(footprint)")
 67→			switch order.Order {
 68→			case model.SortDirectionEnumAsc:
 69→				query = query.OrderBy(fmt.Sprintf("JSON_EXTRACT(footprint, \"$.%s\") ASC", field))
 70→			case model.SortDirectionEnumDesc:
 71→				query = query.OrderBy(fmt.Sprintf("JSON_EXTRACT(footprint, \"$.%s\") DESC", field))
 72→			default:
 73→				return nil, errors.New("invalid sorting order for footprint")
 74→			}
 75→		}
 76→	}
 77→
 78→	if page != nil && page.ItemsPerPage != -1 {
 79→		limit := uint64(page.ItemsPerPage)
 80→		query = query.Offset((uint64(page.Page) - 1) * limit).Limit(limit)
 81→	}
 82→
 83→	for _, f := range filters {
 84→		query = BuildWhereClause(f, query)
 85→	}
 86→
 87→	rows, err := query.RunWith(r.stmtCache).QueryContext(ctx)
 88→	if err != nil {
 89→		queryString, queryVars, _ := query.ToSql()
 90→		return nil, fmt.Errorf("query failed [%s] %v: %w", queryString, queryVars, err)
 91→	}
 92→	defer rows.Close()
 93→
 94→	jobs := make([]*schema.Job, 0, defaultJobsCapacity)
 95→	for rows.Next() {
 96→		job, err := scanJob(rows)
 97→		if err != nil {
 98→			cclog.Warnf("Error scanning job row: %v", err)
 99→			return nil, fmt.Errorf("failed to scan job row: %w", err)
100→		}
101→		jobs = append(jobs, job)
102→	}
103→
104→	if err := rows.Err(); err != nil {
105→		return nil, fmt.Errorf("error iterating job rows: %w", err)
106→	}
107→
108→	return jobs, nil
109→}
110→
111→// CountJobs returns the total number of jobs matching the given filters.
112→// Security controls are automatically applied based on the user context.
113→// Uses DISTINCT count to handle tag filters correctly (jobs may appear multiple
114→// times when joined with the tag table).
115→func (r *JobRepository) CountJobs(
116→	ctx context.Context,
117→	filters []*model.JobFilter,
118→) (int, error) {
119→	query, qerr := SecurityCheck(ctx, sq.Select("count(DISTINCT job.id)").From("job"))
120→	if qerr != nil {
121→		return 0, qerr
122→	}
123→
124→	for _, f := range filters {
125→		query = BuildWhereClause(f, query)
126→	}
127→
128→	var count int
129→	if err := query.RunWith(r.DB).QueryRowContext(ctx).Scan(&count); err != nil {
130→		return 0, fmt.Errorf("failed to count jobs: %w", err)
131→	}
132→
133→	return count, nil
134→}
135→
136→// SecurityCheckWithUser applies role-based access control filters to a job query
137→// based on the provided user's roles and permissions.
138→//
139→// Access rules by role:
140→//   - API role (exclusive): Full access to all jobs
141→//   - Admin/Support roles: Full access to all jobs
142→//   - Manager role: Access to jobs in managed projects plus own jobs
143→//   - User role: Access only to own jobs
144→//
145→// Returns an error if the user is nil or has no recognized roles.
146→func SecurityCheckWithUser(user *schema.User, query sq.SelectBuilder) (sq.SelectBuilder, error) {
147→	if user == nil {
148→		var qnil sq.SelectBuilder
149→		return qnil, fmt.Errorf("user context is nil")
150→	}
151→
152→	switch {
153→	case len(user.Roles) == 1 && user.HasRole(schema.RoleAPI):
154→		return query, nil
155→	case user.HasAnyRole([]schema.Role{schema.RoleAdmin, schema.RoleSupport}):
156→		return query, nil
157→	case user.HasRole(schema.RoleManager):
158→		if len(user.Projects) != 0 {
159→			return query.Where(sq.Or{sq.Eq{"job.project": user.Projects}, sq.Eq{"job.hpc_user": user.Username}}), nil
160→		}
161→		cclog.Debugf("Manager '%s' has no assigned projects, restricting to personal jobs", user.Username)
162→		return query.Where("job.hpc_user = ?", user.Username), nil
163→	case user.HasRole(schema.RoleUser):
164→		return query.Where("job.hpc_user = ?", user.Username), nil
165→	default:
166→		var qnil sq.SelectBuilder
167→		return qnil, fmt.Errorf("user has no or unknown roles")
168→	}
169→}
170→
171→// SecurityCheck extracts the user from the context and applies role-based access
172→// control filters to the query. This is a convenience wrapper around SecurityCheckWithUser.
173→func SecurityCheck(ctx context.Context, query sq.SelectBuilder) (sq.SelectBuilder, error) {
174→	user := GetUserFromContext(ctx)
175→	return SecurityCheckWithUser(user, query)
176→}
177→
178→// BuildWhereClause constructs SQL WHERE conditions from a JobFilter and applies
179→// them to the query. Supports filtering by job properties (cluster, state, user),
180→// time ranges, resource usage, tags, and JSON field searches in meta_data,
181→// footprint, and resources columns.
182→func BuildWhereClause(filter *model.JobFilter, query sq.SelectBuilder) sq.SelectBuilder {
183→	// Primary Key
184→	if filter.DbID != nil {
185→		dbIDs := make([]string, len(filter.DbID))
186→		copy(dbIDs, filter.DbID)
187→		query = query.Where(sq.Eq{"job.id": dbIDs})
188→	}
189→	// Explicit indices
190→	if filter.Cluster != nil {
191→		query = buildStringCondition("job.cluster", filter.Cluster, query)
192→	}
193→	if filter.SubCluster != nil {
194→		query = buildStringCondition("job.subcluster", filter.SubCluster, query)
195→	}
196→	if filter.Partition != nil {
197→		query = buildStringCondition("job.cluster_partition", filter.Partition, query)
198→	}
199→	if filter.State != nil {
200→		if len(filter.State) == 1 {
201→			singleStat := string(filter.State[0])
202→			query = query.Where("job.job_state = ?", singleStat)
203→		} else {
204→			states := make([]string, len(filter.State))
205→			for i, val := range filter.State {
206→				states[i] = string(val)
207→			}
208→			query = query.Where(sq.Eq{"job.job_state": states})
209→		}
210→	}
211→	if filter.Shared != nil {
212→		query = query.Where("job.shared = ?", *filter.Shared)
213→	}
214→	if filter.Project != nil {
215→		query = buildStringCondition("job.project", filter.Project, query)
216→	}
217→	if filter.User != nil {
218→		query = buildStringCondition("job.hpc_user", filter.User, query)
219→	}
220→	if filter.NumNodes != nil {
221→		query = buildIntCondition("job.num_nodes", filter.NumNodes, query)
222→	}
223→	if filter.NumAccelerators != nil {
224→		query = buildIntCondition("job.num_acc", filter.NumAccelerators, query)
225→	}
226→	if filter.NumHWThreads != nil {
227→		query = buildIntCondition("job.num_hwthreads", filter.NumHWThreads, query)
228→	}
229→	if filter.ArrayJobID != nil {
230→		query = query.Where("job.array_job_id = ?", *filter.ArrayJobID)
231→	}
232→	if filter.StartTime != nil {
233→		query = buildTimeCondition("job.start_time", filter.StartTime, query)
234→	}
235→	if filter.Duration != nil {
236→		query = buildIntCondition("job.duration", filter.Duration, query)
237→	}
238→	if filter.Energy != nil {
239→		query = buildFloatCondition("job.energy", filter.Energy, query)
240→	}
241→	// Indices on Tag Table
242→	if filter.Tags != nil {
243→		// This is an OR-Logic query: Returns all distinct jobs with at least one of the requested tags; TODO: AND-Logic query?
244→		query = query.Join("jobtag ON jobtag.job_id = job.id").Where(sq.Eq{"jobtag.tag_id": filter.Tags}).Distinct()
245→	}
246→	// No explicit Indices
247→	if filter.JobID != nil {
248→		query = buildStringCondition("job.job_id", filter.JobID, query)
249→	}
250→	// Queries Within JSONs
251→	if filter.MetricStats != nil {
252→		for _, ms := range filter.MetricStats {
253→			query = buildFloatJSONCondition(ms.MetricName, ms.Range, query)
254→		}
255→	}
256→	if filter.Node != nil {
257→		query = buildResourceJSONCondition("hostname", filter.Node, query)
258→	}
259→	if filter.JobName != nil {
260→		query = buildMetaJSONCondition("jobName", filter.JobName, query)
261→	}
262→	if filter.Schedule != nil {
263→		interactiveJobname := "interactive"
264→		switch *filter.Schedule {
265→		case "interactive":
266→			iFilter := model.StringInput{Eq: &interactiveJobname}
267→			query = buildMetaJSONCondition("jobName", &iFilter, query)
268→		case "batch":
269→			sFilter := model.StringInput{Neq: &interactiveJobname}
270→			query = buildMetaJSONCondition("jobName", &sFilter, query)
271→		}
272→	}
273→
274→	// Configurable Filter to exclude recently started jobs, see config.go: ShortRunningJobsDuration
275→	if filter.MinRunningFor != nil {
276→		now := time.Now().Unix()
277→		// Only jobs whose start timestamp is more than MinRunningFor seconds in the past
278→		// If a job completed within the configured timeframe, it will still show up after the start_time matches the condition!
279→		query = query.Where(sq.Lt{"job.start_time": (now - int64(*filter.MinRunningFor))})
280→	}
281→	return query
282→}
283→
284→// buildIntCondition creates clauses for integer range filters, using BETWEEN only if required.
285→func buildIntCondition(field string, cond *config.IntRange, query sq.SelectBuilder) sq.SelectBuilder {
286→	if cond.From != 1 && cond.To != 0 {
287→		return query.Where(field+" BETWEEN ? AND ?", cond.From, cond.To)
288→	} else if cond.From != 1 && cond.To == 0 {
289→		return query.Where(field+" >= ?", cond.From)
290→	} else if cond.From == 1 && cond.To != 0 {
291→		return query.Where(field+" <= ?", cond.To)
292→	} else {
293→		return query
294→	}
295→}
296→
297→// buildFloatCondition creates a clauses for float range filters, using BETWEEN only if required.
298→func buildFloatCondition(field string, cond *model.FloatRange, query sq.SelectBuilder) sq.SelectBuilder {
299→	if cond.From != 1.0 && cond.To != 0.0 {
300→		return query.Where(field+" BETWEEN ? AND ?", cond.From, cond.To)
301→	} else if cond.From != 1.0 && cond.To == 0.0 {
302→		return query.Where(field+" >= ?", cond.From)
303→	} else if cond.From == 1.0 && cond.To != 0.0 {
304→		return query.Where(field+" <= ?", cond.To)
305→	} else {
306→		return query
307→	}
308→}
309→
310→// buildTimeCondition creates time range filters supporting absolute timestamps,
311→// relative time ranges (last6h, last24h, last7d, last30d), or open-ended ranges.
312→// Reminder: BETWEEN Queries are slower and dont use indices as frequently: Only use if both conditions required
313→func buildTimeCondition(field string, cond *config.TimeRange, query sq.SelectBuilder) sq.SelectBuilder {
314→	if cond.From != nil && cond.To != nil {
315→		return query.Where(field+" BETWEEN ? AND ?", cond.From.Unix(), cond.To.Unix())
316→	} else if cond.From != nil {
317→		return query.Where(field+" >= ?", cond.From.Unix())
318→	} else if cond.To != nil {
319→		return query.Where(field+" <= ?", cond.To.Unix())
320→	} else if cond.Range != "" {
321→		now := time.Now().Unix()
322→		var then int64
323→		switch cond.Range {
324→		case "last6h":
325→			then = now - (60 * 60 * 6)
326→		case "last24h":
327→			then = now - (60 * 60 * 24)
328→		case "last7d":
329→			then = now - (60 * 60 * 24 * 7)
330→		case "last30d":
331→			then = now - (60 * 60 * 24 * 30)
332→		default:
333→			cclog.Debugf("No known named timeRange: startTime.range = %s", cond.Range)
334→			return query
335→		}
336→		return query.Where(field+" >= ?", then)
337→	} else {
338→		return query
339→	}
340→}
341→
342→// buildFloatJSONCondition creates a filter on a numeric field within the footprint JSON column, using BETWEEN only if required.
343→func buildFloatJSONCondition(jsonField string, cond *model.FloatRange, query sq.SelectBuilder) sq.SelectBuilder {
344→	query = query.Where("JSON_VALID(footprint)")
345→	if cond.From != 1.0 && cond.To != 0.0 {
346→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") BETWEEN ? AND ?", cond.From, cond.To)
347→	} else if cond.From != 1.0 && cond.To == 0.0 {
348→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") >= ?", cond.From)
349→	} else if cond.From == 1.0 && cond.To != 0.0 {
350→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") <= ?", cond.To)
351→	} else {
352→		return query
353→	}
354→}
355→
356→// buildStringCondition creates filters for string fields supporting equality,
357→// inequality, prefix, suffix, substring, and IN list matching.
358→func buildStringCondition(field string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
359→	if cond.Eq != nil {
360→		return query.Where(field+" = ?", *cond.Eq)
361→	}
362→	if cond.Neq != nil {
363→		return query.Where(field+" != ?", *cond.Neq)
364→	}
365→	if cond.StartsWith != nil {
366→		return query.Where(field+" LIKE ?", fmt.Sprint(*cond.StartsWith, "%"))
367→	}
368→	if cond.EndsWith != nil {
369→		return query.Where(field+" LIKE ?", fmt.Sprint("%", *cond.EndsWith))
370→	}
371→	if cond.Contains != nil {
372→		return query.Where(field+" LIKE ?", fmt.Sprint("%", *cond.Contains, "%"))
373→	}
374→	if cond.In != nil {
375→		queryElements := make([]string, len(cond.In))
376→		copy(queryElements, cond.In)
377→		return query.Where(sq.Or{sq.Eq{field: queryElements}})
378→	}
379→	return query
380→}
381→
382→// buildMetaJSONCondition creates filters on fields within the meta_data JSON column.
383→func buildMetaJSONCondition(jsonField string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
384→	query = query.Where("JSON_VALID(meta_data)")
385→	if cond.Eq != nil {
386→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") = ?", *cond.Eq)
387→	}
388→	if cond.Neq != nil {
389→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") != ?", *cond.Neq)
390→	}
391→	if cond.StartsWith != nil {
392→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") LIKE ?", fmt.Sprint(*cond.StartsWith, "%"))
393→	}
394→	if cond.EndsWith != nil {
395→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") LIKE ?", fmt.Sprint("%", *cond.EndsWith))
396→	}
397→	if cond.Contains != nil {
398→		return query.Where("JSON_EXTRACT(meta_data, \"$."+jsonField+"\") LIKE ?", fmt.Sprint("%", *cond.Contains, "%"))
399→	}
400→	return query
401→}
402→
403→// buildResourceJSONCondition creates filters on fields within the resources JSON array column.
404→// Uses json_each to search within array elements.
405→func buildResourceJSONCondition(jsonField string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
406→	query = query.Where("JSON_VALID(resources)")
