 601→// Jobs is the resolver for the jobs field.
 602→func (r *queryResolver) Jobs(ctx context.Context, filter []*model.JobFilter, page *model.PageRequest, order *model.OrderByInput) (*model.JobResultList, error) {
 603→	if page == nil {
 604→		page = &model.PageRequest{
 605→			ItemsPerPage: 50,
 606→			Page:         1,
 607→		}
 608→	}
 609→
 610→	jobs, err := r.Repo.QueryJobs(ctx, filter, page, order)
 611→	if err != nil {
 612→		cclog.Warn("Error while querying jobs")
 613→		return nil, err
 614→	}
 615→
 616→	count, err := r.Repo.CountJobs(ctx, filter)
 617→	if err != nil {
 618→		cclog.Warn("Error while counting jobs")
 619→		return nil, err
 620→	}
 621→
 622→	// Note: Even if App-Default 'config.Keys.UiDefaults["job_list_usePaging"]' is set, always return hasNextPage boolean.
 623→	// Users can decide in frontend to use continuous scroll, even if app-default is paging!
 624→	// Skip if page.ItemsPerPage == -1 ("Load All" -> No Next Page required, Status Dashboards)
 625→	/*
 626→	  Example Page 4 @ 10 IpP : Does item 41 exist?
 627→	  Minimal Page 41 @ 1 IpP : If len(result) is 1, Page 5 @ 10 IpP exists.
 628→	*/
 629→	hasNextPage := false
 630→	if page.ItemsPerPage != -1 {
 631→		nextPage := &model.PageRequest{
 632→			ItemsPerPage: 1,
 633→			Page:         ((page.Page * page.ItemsPerPage) + 1),
 634→		}
 635→		nextJobs, err := r.Repo.QueryJobs(ctx, filter, nextPage, order)
 636→		if err != nil {
 637→			cclog.Warn("Error while querying next jobs")
 638→			return nil, err
 639→		}
 640→		hasNextPage = len(nextJobs) == 1
 641→	}
 642→
 643→	return &model.JobResultList{Items: jobs, Count: &count, HasNextPage: &hasNextPage}, nil
 644→}
