 646→// JobsStatistics is the resolver for the jobsStatistics field.
 647→func (r *queryResolver) JobsStatistics(ctx context.Context, filter []*model.JobFilter, metrics []string, page *model.PageRequest, sortBy *model.SortByAggregate, groupBy *model.Aggregate, numDurationBins *string, numMetricBins *int) ([]*model.JobsStatistics, error) {
 648→	var err error
 649→	var stats []*model.JobsStatistics
 650→
 651→	// Top Level Defaults
 652→	defaultDurationBins := "1h"
 653→	defaultMetricBins := 10
 654→
 655→	// Build requested fields map for selective column computation
 656→	statsFields := []string{
 657→		"totalJobs", "totalUsers", "totalWalltime", "totalNodes", "totalCores",
 658→		"totalAccs", "totalNodeHours", "totalCoreHours", "totalAccHours", "runningJobs", "shortJobs",
 659→	}
 660→	reqFields := make(map[string]bool, len(statsFields))
 661→	fetchedMainStats := false
 662→	for _, f := range statsFields {
 663→		if requireField(ctx, f) {
 664→			reqFields[f] = true
 665→			if f != "runningJobs" && f != "shortJobs" {
 666→				fetchedMainStats = true
 667→			}
 668→		}
 669→	}
 670→
 671→	if fetchedMainStats {
 672→		if groupBy == nil {
 673→			stats, err = r.Repo.JobsStats(ctx, filter, reqFields)
 674→		} else {
 675→			startGrouped := time.Now()
 676→			stats, err = r.Repo.JobsStatsGrouped(ctx, filter, page, sortBy, groupBy, reqFields)
 677→			cclog.Infof("Timer JobsStatsGrouped call: %s", time.Since(startGrouped))
 678→		}
 679→	} else {
 680→		stats = make([]*model.JobsStatistics, 0, 1)
 681→		stats = append(stats, &model.JobsStatistics{})
 682→	}
 683→
 684→	// runningJobs and shortJobs are already inlined in JobsStats/JobsStatsGrouped.
 685→	// Only run separate count queries if main stats were not fetched.
 686→	if !fetchedMainStats {
 687→		if groupBy != nil {
 688→			if requireField(ctx, "shortJobs") {
 689→				stats, err = r.Repo.AddJobCountGrouped(ctx, filter, groupBy, stats, "short")
 690→			}
 691→			if requireField(ctx, "runningJobs") {
 692→				stats, err = r.Repo.AddJobCountGrouped(ctx, filter, groupBy, stats, "running")
 693→			}
 694→		} else {
 695→			if requireField(ctx, "shortJobs") {
 696→				stats, err = r.Repo.AddJobCount(ctx, filter, stats, "short")
 697→			}
 698→			if requireField(ctx, "runningJobs") {
 699→				stats, err = r.Repo.AddJobCount(ctx, filter, stats, "running")
 700→			}
 701→		}
 702→	}
 703→
 704→	if err != nil {
 705→		return nil, err
 706→	}
 707→
 708→	if requireField(ctx, "histDuration") || requireField(ctx, "histNumNodes") || requireField(ctx, "histNumCores") || requireField(ctx, "histNumAccs") {
 709→
 710→		if numDurationBins == nil {
 711→			numDurationBins = &defaultDurationBins
 712→		}
 713→
 714→		if groupBy == nil {
 715→			stats[0], err = r.Repo.AddHistograms(ctx, filter, stats[0], numDurationBins)
 716→			if err != nil {
 717→				return nil, err
 718→			}
 719→		} else {
 720→			return nil, errors.New("histograms only implemented without groupBy argument")
 721→		}
 722→	}
 723→
 724→	if requireField(ctx, "histMetrics") {
 725→
 726→		if numMetricBins == nil {
 727→			numMetricBins = &defaultMetricBins
 728→		}
 729→
 730→		if groupBy == nil {
 731→			stats[0], err = r.Repo.AddMetricHistograms(ctx, filter, metrics, stats[0], numMetricBins)
 732→			if err != nil {
 733→				return nil, err
 734→			}
 735→		} else {
 736→			return nil, errors.New("metric histograms only implemented without groupBy argument")
 737→		}
 738→	}
 739→
 740→	return stats, nil
 741→}
