 805→func (r *queryResolver) NodeMetrics(ctx context.Context, cluster string, nodes []string, scopes []schema.MetricScope, metrics []string, from time.Time, to time.Time) ([]*model.NodeMetrics, error) {
 806→	user := repository.GetUserFromContext(ctx)
 807→	if user != nil && !user.HasAnyRole([]schema.Role{schema.RoleAdmin, schema.RoleSupport}) {
 808→		return nil, errors.New("you need to be administrator or support staff for this query")
 809→	}
 810→
 811→	defaultMetrics := make([]string, 0)
 812→	for _, mc := range archive.GetCluster(cluster).MetricConfig {
 813→		defaultMetrics = append(defaultMetrics, mc.Name)
 814→	}
 815→	if metrics == nil {
 816→		metrics = defaultMetrics
 817→	} else {
 818→		metrics = slices.DeleteFunc(metrics, func(metric string) bool {
 819→			return !slices.Contains(defaultMetrics, metric) // Remove undefined metrics.
 820→		})
 821→	}
 822→
 823→	data, err := metricdispatch.LoadNodeData(cluster, metrics, nodes, scopes, from, to, ctx)
 824→	if err != nil {
 825→		cclog.Warn("error while loading node data")
 826→		return nil, err
 827→	}
 828→
 829→	nodeRepo := repository.GetNodeRepository()
 830→	stateMap, _ := nodeRepo.MapNodes(cluster)
 831→
 832→	nodeMetrics := make([]*model.NodeMetrics, 0, len(data))
 833→	for hostname, metrics := range data {
 834→		host := &model.NodeMetrics{
 835→			Host:    hostname,
 836→			State:   stateMap[hostname],
 837→			Metrics: make([]*model.JobMetricWithName, 0, len(metrics)*len(scopes)),
 838→		}
 839→		host.SubCluster, err = archive.GetSubClusterByNode(cluster, hostname)
 840→		if err != nil {
 841→			cclog.Warnf("error in nodeMetrics resolver: %s", err)
 842→		}
 843→
 844→		for metric, scopedMetrics := range metrics {
 845→			for _, scopedMetric := range scopedMetrics {
 846→				host.Metrics = append(host.Metrics, &model.JobMetricWithName{
 847→					Name:   metric,
 848→					Scope:  schema.MetricScopeNode,
 849→					Metric: scopedMetric,
 850→				})
 851→			}
 852→		}
 853→
 854→		nodeMetrics = append(nodeMetrics, host)
 855→	}
 856→
 857→	return nodeMetrics, nil
 858→}
