 944→
 945→	// 'nodes' == nil -> Defaults to all nodes of cluster for existing query workflow
 946→	scopes := []schema.MetricScope{"node"}
 947→	data, err := metricdispatch.LoadNodeData(cluster, metrics, nil, scopes, from, to, ctx)
 948→	if err != nil {
 949→		cclog.Warn("error while loading node data")
 950→		return nil, err
 951→	}
 952→
 953→	clusterMetricData := make([]*model.ClusterMetricWithName, 0)
 954→	clusterMetrics := model.ClusterMetrics{NodeCount: 0, Metrics: clusterMetricData}
 955→
 956→	collectorTimestep := make(map[string]int)
 957→	collectorUnit := make(map[string]schema.Unit)
 958→	collectorData := make(map[string][]schema.Float)
 959→
