 977→					if !okData && len(ser.Data) != 0 {
 978→						collectorData[metric] = make([]schema.Float, len(ser.Data))
 979→					} else if !okData {
 980→						cclog.Debugf("[SCHEMARESOLVER] clusterMetrics skip init: no data -> %s at %s; size %d", metric, ser.Hostname, len(ser.Data))
 981→					}
 982→					// Sum if init'd and matching size
 983→					if okData && len(ser.Data) == len(collectorData[metric]) {
 984→						for i, val := range ser.Data {
 985→							if val.IsNaN() {
 986→								continue
 987→							} else {
 988→								collectorData[metric][i] += val
 989→							}
 990→						}
 991→					} else if okData {
 992→						cclog.Debugf("[SCHEMARESOLVER] clusterMetrics skip sum: data diff -> %s at %s; want size %d, have size %d", metric, ser.Hostname, len(collectorData[metric]), len(ser.Data))
