 23→// Helper function for the rooflineHeatmap GraphQL query placed here so that schema.resolvers.go is not too full.
 24→func (r *queryResolver) rooflineHeatmap(
 25→	ctx context.Context,
 26→	filter []*model.JobFilter,
 27→	rows int, cols int,
 28→	minX float64, minY float64, maxX float64, maxY float64,
 29→) ([][]float64, error) {
 30→	jobs, err := r.Repo.QueryJobs(ctx, filter, &model.PageRequest{Page: 1, ItemsPerPage: MAX_JOBS_FOR_ANALYSIS + 1}, nil)
 31→	if err != nil {
 32→		cclog.Error("Error while querying jobs for roofline")
 33→		return nil, err
 34→	}
 35→	if len(jobs) > MAX_JOBS_FOR_ANALYSIS {
 36→		return nil, fmt.Errorf("GRAPH/UTIL > too many jobs matched (max: %d)", MAX_JOBS_FOR_ANALYSIS)
 37→	}
 38→
 39→	fcols, frows := float64(cols), float64(rows)
 40→	minX, minY, maxX, maxY = math.Log10(minX), math.Log10(minY), math.Log10(maxX), math.Log10(maxY)
 41→	tiles := make([][]float64, rows)
 42→	for i := range tiles {
 43→		tiles[i] = make([]float64, cols)
 44→	}
 45→
 46→	for _, job := range jobs {
 47→		if job.MonitoringStatus == schema.MonitoringStatusDisabled || job.MonitoringStatus == schema.MonitoringStatusArchivingFailed {
 48→			continue
 49→		}
 50→
 51→		// metricConfigs := archive.GetCluster(job.Cluster).MetricConfig
 52→		// resolution := 0
 53→
 54→		// for _, mc := range metricConfigs {
 55→		// 	resolution = max(resolution, mc.Timestep)
 56→		// }
 57→
 58→		jobdata, err := metricdispatch.LoadData(job, []string{"flops_any", "mem_bw"}, []schema.MetricScope{schema.MetricScopeNode}, ctx, 0)
 59→		if err != nil {
 60→			cclog.Warnf("Error while loading roofline metrics for job %d", *job.ID)
 61→			return nil, err
 62→		}
 63→
 64→		flops_, membw_ := jobdata["flops_any"], jobdata["mem_bw"]
 65→		if flops_ == nil && membw_ == nil {
 66→			cclog.Warnf("rooflineHeatmap(): 'flops_any' or 'mem_bw' missing for job %d", *job.ID)
 67→			continue
 68→			// return nil, fmt.Errorf("GRAPH/UTIL > 'flops_any' or 'mem_bw' missing for job %d", job.ID)
 69→		}
 70→
 71→		flops, ok1 := flops_["node"]
 72→		membw, ok2 := membw_["node"]
 73→		if !ok1 || !ok2 {
 74→			cclog.Info("rooflineHeatmap() query not implemented for where flops_any or mem_bw not available at 'node' level")
 75→			continue
 76→			// TODO/FIXME:
 77→			// return nil, errors.New("GRAPH/UTIL > todo: rooflineHeatmap() query not implemented for where flops_any or mem_bw not available at 'node' level")
 78→		}
 79→
 80→		for n := 0; n < len(flops.Series); n++ {
 81→			flopsSeries, membwSeries := flops.Series[n], membw.Series[n]
 82→			for i := 0; i < len(flopsSeries.Data); i++ {
 83→				if i >= len(membwSeries.Data) {
 84→					break
 85→				}
 86→
 87→				x, y := math.Log10(float64(flopsSeries.Data[i]/membwSeries.Data[i])), math.Log10(float64(flopsSeries.Data[i]))
 88→				if math.IsNaN(x) || math.IsNaN(y) || x < minX || x >= maxX || y < minY || y > maxY {
 89→					continue
 90→				}
 91→
 92→				x, y = math.Floor(((x-minX)/(maxX-minX))*fcols), math.Floor(((y-minY)/(maxY-minY))*frows)
 93→				if x < 0 || x >= fcols || y < 0 || y >= frows {
 94→					continue
 95→				}
 96→
 97→				tiles[int(y)][int(x)] += 1
 98→			}
 99→		}
100→	}
101→
102→	return tiles, nil
103→}
