111→// CountJobs returns the total number of jobs matching the given filters.
112→// Security controls are automatically applied based on the user context.
113→// Uses DISTINCT count to handle tag filters correctly (jobs may appear multiple
114→// times when joined with the tag table).
115→func (r *JobRepository) CountJobs(
116→	ctx context.Context,
117→	filters []*model.JobFilter,
118→) (int, error) {
119→	query, qerr := SecurityCheck(ctx, sq.Select("count(DISTINCT job.id)").From("job"))
120→	if qerr != nil {
121→		return 0, qerr
122→	}
123→
124→	for _, f := range filters {
125→		query = BuildWhereClause(f, query)
126→	}
127→
128→	var count int
129→	if err := query.RunWith(r.DB).QueryRowContext(ctx).Scan(&count); err != nil {
130→		return 0, fmt.Errorf("failed to count jobs: %w", err)
131→	}
132→
133→	return count, nil
134→}
