171→// SecurityCheck extracts the user from the context and applies role-based access
172→// control filters to the query. This is a convenience wrapper around SecurityCheckWithUser.
173→func SecurityCheck(ctx context.Context, query sq.SelectBuilder) (sq.SelectBuilder, error) {
174→	user := GetUserFromContext(ctx)
175→	return SecurityCheckWithUser(user, query)
176→}
