178→// BuildWhereClause constructs SQL WHERE conditions from a JobFilter and applies
179→// them to the query. Supports filtering by job properties (cluster, state, user),
180→// time ranges, resource usage, tags, and JSON field searches in meta_data,
181→// footprint, and resources columns.
182→func BuildWhereClause(filter *model.JobFilter, query sq.SelectBuilder) sq.SelectBuilder {
183→	// Primary Key
184→	if filter.DbID != nil {
185→		dbIDs := make([]string, len(filter.DbID))
186→		copy(dbIDs, filter.DbID)
187→		query = query.Where(sq.Eq{"job.id": dbIDs})
188→	}
189→	// Explicit indices
190→	if filter.Cluster != nil {
191→		query = buildStringCondition("job.cluster", filter.Cluster, query)
192→	}
193→	if filter.SubCluster != nil {
194→		query = buildStringCondition("job.subcluster", filter.SubCluster, query)
195→	}
196→	if filter.Partition != nil {
197→		query = buildStringCondition("job.cluster_partition", filter.Partition, query)
198→	}
199→	if filter.State != nil {
200→		if len(filter.State) == 1 {
201→			// Inline literal value so SQLite can match partial indexes (WHERE job_state = 'running').
202→			// Safe: values come from validated GraphQL enum (model.JobState).
203→			singleStat := string(filter.State[0])
204→			query = query.Where(fmt.Sprintf("job.job_state = '%s'", singleStat))
205→		} else {
206→			states := make([]string, len(filter.State))
207→			for i, val := range filter.State {
208→				states[i] = string(val)
209→			}
210→			query = query.Where(sq.Eq{"job.job_state": states})
211→		}
212→	}
213→	if filter.Shared != nil {
214→		query = query.Where("job.shared = ?", *filter.Shared)
215→	}
216→	if filter.Project != nil {
217→		query = buildStringCondition("job.project", filter.Project, query)
218→	}
219→	if filter.User != nil {
220→		query = buildStringCondition("job.hpc_user", filter.User, query)
221→	}
222→	if filter.NumNodes != nil {
223→		query = buildIntCondition("job.num_nodes", filter.NumNodes, query)
224→	}
225→	if filter.NumAccelerators != nil {
226→		query = buildIntCondition("job.num_acc", filter.NumAccelerators, query)
227→	}
228→	if filter.NumHWThreads != nil {
229→		query = buildIntCondition("job.num_hwthreads", filter.NumHWThreads, query)
230→	}
231→	if filter.ArrayJobID != nil {
232→		query = query.Where("job.array_job_id = ?", *filter.ArrayJobID)
233→	}
234→	if filter.StartTime != nil {
235→		query = buildTimeCondition("job.start_time", filter.StartTime, query)
236→	}
237→	if filter.Duration != nil {
238→		query = buildIntCondition("job.duration", filter.Duration, query)
239→	}
240→	if filter.Energy != nil {
241→		query = buildFloatCondition("job.energy", filter.Energy, query)
242→	}
243→	// Indices on Tag Table
244→	if filter.Tags != nil {
245→		// This is an OR-Logic query: Returns all distinct jobs with at least one of the requested tags; TODO: AND-Logic query?
246→		query = query.Join("jobtag ON jobtag.job_id = job.id").Where(sq.Eq{"jobtag.tag_id": filter.Tags}).Distinct()
247→	}
248→	// No explicit Indices
249→	if filter.JobID != nil {
250→		query = buildStringCondition("job.job_id", filter.JobID, query)
251→	}
252→	// Queries Within JSONs
253→	if filter.MetricStats != nil {
254→		for _, ms := range filter.MetricStats {
255→			query = buildFloatJSONCondition(ms.MetricName, ms.Range, query)
256→		}
257→	}
258→	if filter.Node != nil {
259→		query = buildResourceJSONCondition("hostname", filter.Node, query)
260→	}
261→	if filter.JobName != nil {
262→		query = buildMetaJSONCondition("jobName", filter.JobName, query)
263→	}
264→	if filter.Schedule != nil {
265→		interactiveJobname := "interactive"
266→		switch *filter.Schedule {
267→		case "interactive":
268→			iFilter := model.StringInput{Eq: &interactiveJobname}
269→			query = buildMetaJSONCondition("jobName", &iFilter, query)
270→		case "batch":
271→			sFilter := model.StringInput{Neq: &interactiveJobname}
272→			query = buildMetaJSONCondition("jobName", &sFilter, query)
273→		}
274→	}
275→
276→	// Configurable Filter to exclude recently started jobs, see config.go: ShortRunningJobsDuration
277→	if filter.MinRunningFor != nil {
278→		now := time.Now().Unix()
279→		// Only jobs whose start timestamp is more than MinRunningFor seconds in the past
280→		// If a job completed within the configured timeframe, it will still show up after the start_time matches the condition!
281→		query = query.Where(sq.Lt{"job.start_time": (now - int64(*filter.MinRunningFor))})
282→	}
283→	return query
284→}
