286→// buildIntCondition creates clauses for integer range filters, using BETWEEN only if required.
287→func buildIntCondition(field string, cond *config.IntRange, query sq.SelectBuilder) sq.SelectBuilder {
288→	if cond.From != 1 && cond.To != 0 {
289→		return query.Where(field+" BETWEEN ? AND ?", cond.From, cond.To)
290→	} else if cond.From != 1 && cond.To == 0 {
291→		return query.Where(field+" >= ?", cond.From)
292→	} else if cond.From == 1 && cond.To != 0 {
293→		return query.Where(field+" <= ?", cond.To)
294→	} else {
295→		return query
296→	}
297→}
298→
299→// buildFloatCondition creates a clauses for float range filters, using BETWEEN only if required.
300→func buildFloatCondition(field string, cond *model.FloatRange, query sq.SelectBuilder) sq.SelectBuilder {
301→	if cond.From != 1.0 && cond.To != 0.0 {
302→		return query.Where(field+" BETWEEN ? AND ?", cond.From, cond.To)
303→	} else if cond.From != 1.0 && cond.To == 0.0 {
304→		return query.Where(field+" >= ?", cond.From)
305→	} else if cond.From == 1.0 && cond.To != 0.0 {
306→		return query.Where(field+" <= ?", cond.To)
307→	} else {
308→		return query
309→	}
310→}
