312→// buildTimeCondition creates time range filters supporting absolute timestamps,
313→// relative time ranges (last6h, last24h, last7d, last30d), or open-ended ranges.
314→// Reminder: BETWEEN Queries are slower and dont use indices as frequently: Only use if both conditions required
315→func buildTimeCondition(field string, cond *config.TimeRange, query sq.SelectBuilder) sq.SelectBuilder {
316→	if cond.From != nil && cond.To != nil {
317→		return query.Where(field+" BETWEEN ? AND ?", cond.From.Unix(), cond.To.Unix())
318→	} else if cond.From != nil {
319→		return query.Where(field+" >= ?", cond.From.Unix())
320→	} else if cond.To != nil {
321→		return query.Where(field+" <= ?", cond.To.Unix())
322→	} else if cond.Range != "" {
323→		now := time.Now().Unix()
324→		var then int64
325→		switch cond.Range {
326→		case "last6h":
327→			then = now - (60 * 60 * 6)
328→		case "last24h":
329→			then = now - (60 * 60 * 24)
330→		case "last7d":
331→			then = now - (60 * 60 * 24 * 7)
332→		case "last30d":
333→			then = now - (60 * 60 * 24 * 30)
334→		default:
335→			cclog.Debugf("No known named timeRange: startTime.range = %s", cond.Range)
336→			return query
337→		}
338→		return query.Where(field+" >= ?", then)
339→	} else {
340→		return query
341→	}
342→}
