344→// buildFloatJSONCondition creates a filter on a numeric field within the footprint JSON column, using BETWEEN only if required.
345→func buildFloatJSONCondition(jsonField string, cond *model.FloatRange, query sq.SelectBuilder) sq.SelectBuilder {
346→	query = query.Where("JSON_VALID(footprint)")
347→	if cond.From != 1.0 && cond.To != 0.0 {
348→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") BETWEEN ? AND ?", cond.From, cond.To)
349→	} else if cond.From != 1.0 && cond.To == 0.0 {
350→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") >= ?", cond.From)
351→	} else if cond.From == 1.0 && cond.To != 0.0 {
352→		return query.Where("JSON_EXTRACT(footprint, \"$."+jsonField+"\") <= ?", cond.To)
353→	} else {
354→		return query
355→	}
356→}
