358→// buildStringCondition creates filters for string fields supporting equality,
359→// inequality, prefix, suffix, substring, and IN list matching.
360→func buildStringCondition(field string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
361→	if cond.Eq != nil {
362→		return query.Where(field+" = ?", *cond.Eq)
363→	}
364→	if cond.Neq != nil {
365→		return query.Where(field+" != ?", *cond.Neq)
366→	}
367→	if cond.StartsWith != nil {
368→		return query.Where(field+" LIKE ?", fmt.Sprint(*cond.StartsWith, "%"))
369→	}
370→	if cond.EndsWith != nil {
371→		return query.Where(field+" LIKE ?", fmt.Sprint("%", *cond.EndsWith))
372→	}
373→	if cond.Contains != nil {
374→		return query.Where(field+" LIKE ?", fmt.Sprint("%", *cond.Contains, "%"))
375→	}
376→	if cond.In != nil {
377→		queryElements := make([]string, len(cond.In))
378→		copy(queryElements, cond.In)
379→		return query.Where(sq.Or{sq.Eq{field: queryElements}})
380→	}
381→	return query
382→}
