405→// buildResourceJSONCondition creates filters on fields within the resources JSON array column.
406→// Uses json_each to search within array elements.
407→func buildResourceJSONCondition(jsonField string, cond *model.StringInput, query sq.SelectBuilder) sq.SelectBuilder {
408→	query = query.Where("JSON_VALID(resources)")
409→	if cond.Eq != nil {
410→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") = ?)", *cond.Eq)
411→	}
412→	if cond.Neq != nil { // Currently Unused
413→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") != ?)", *cond.Neq)
414→	}
415→	if cond.StartsWith != nil { // Currently Unused
416→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\")) LIKE ?)", fmt.Sprint(*cond.StartsWith, "%"))
417→	}
418→	if cond.EndsWith != nil { // Currently Unused
419→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") LIKE ?)", fmt.Sprint("%", *cond.EndsWith))
420→	}
421→	if cond.Contains != nil {
422→		return query.Where("EXISTS (SELECT 1 FROM json_each(job.resources) WHERE json_extract(value, \"$."+jsonField+"\") LIKE ?)", fmt.Sprint("%", *cond.Contains, "%"))
423→	}
424→	return query
