432→// toSnakeCase converts camelCase strings to snake_case for SQL column names.
433→// Includes security checks to prevent SQL injection attempts.
434→// Panics if potentially dangerous characters are detected.
435→func toSnakeCase(str string) string {
436→	for _, c := range str {
437→		if c == '\'' || c == '\\' || c == '"' || c == ';' || c == '-' || c == ' ' {
438→			cclog.Panicf("toSnakeCase: potentially dangerous character detected in input: %q", str)
439→		}
440→	}
441→
442→	snake := matchFirstCap.ReplaceAllString(str, "${1}_${2}")
443→	snake = matchAllCap.ReplaceAllString(snake, "${1}_${2}")
444→	return strings.ToLower(snake)
445→}
